import{_ as s,c as a,o as n,a as e}from"./app.f79ee0bc.js";const A=JSON.parse('{"title":"Concurrency","description":"","frontmatter":{},"headers":[{"level":2,"title":"The Problem","slug":"the-problem","link":"#the-problem","children":[]},{"level":2,"title":"Layer 1 \u2014 Redis Distributed Lock (fail fast)","slug":"layer-1-\u2014-redis-distributed-lock-fail-fast","link":"#layer-1-\u2014-redis-distributed-lock-fail-fast","children":[{"level":3,"title":"What Redis protects against","slug":"what-redis-protects-against","link":"#what-redis-protects-against","children":[]},{"level":3,"title":"What Redis does not guarantee","slug":"what-redis-does-not-guarantee","link":"#what-redis-does-not-guarantee","children":[]}]},{"level":2,"title":"Layer 2 \u2014 Optimistic Concurrency (correctness guarantee)","slug":"layer-2-\u2014-optimistic-concurrency-correctness-guarantee","link":"#layer-2-\u2014-optimistic-concurrency-correctness-guarantee","children":[{"level":3,"title":"What optimistic concurrency protects against","slug":"what-optimistic-concurrency-protects-against","link":"#what-optimistic-concurrency-protects-against","children":[]}]},{"level":2,"title":"Why Both Layers","slug":"why-both-layers","link":"#why-both-layers","children":[]},{"level":2,"title":"Concurrency Test","slug":"concurrency-test","link":"#concurrency-test","children":[]}],"relativePath":"concurrency.md"}'),l={name:"concurrency.md"},o=e(`<h1 id="concurrency" tabindex="-1">Concurrency <a class="header-anchor" href="#concurrency" aria-hidden="true">#</a></h1><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-hidden="true">#</a></h2><p>A ticketing system is a classic concurrency target \u2014 multiple users can attempt to book the same seat at the same time. Without protection, two requests could both read a seat as <code>Available</code>, both pass the availability check, and both succeed, resulting in an oversold seat.</p><p>This system uses two complementary layers to prevent this.</p><hr><h2 id="layer-1-\u2014-redis-distributed-lock-fail-fast" tabindex="-1">Layer 1 \u2014 Redis Distributed Lock (fail fast) <a class="header-anchor" href="#layer-1-\u2014-redis-distributed-lock-fail-fast" aria-hidden="true">#</a></h2><p>When a reservation request arrives, before touching the database, each requested seat is locked in Redis:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">POST /api/Reservations</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2502</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 TryLockSeatAsync(screeningId, seatId)</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2502       \u2514\u2500\u2500 SET lock:screening:{id}:seat:{id} {token} NX EX 10</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2502</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 if lock fails \u2192 release all acquired locks \u2192 return 409</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2502</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2514\u2500\u2500 if all locks acquired \u2192 proceed to DB write</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>Key properties of the lock:</p><ul><li><strong>NX (set if not exists)</strong> \u2014 atomic, only one caller wins</li><li><strong>TTL: 10 seconds</strong> \u2014 lock auto-expires if the process crashes before releasing</li><li><strong>Unique token per lock</strong> \u2014 prevents a caller from releasing a lock it doesn&#39;t own</li><li><strong>All-or-nothing</strong> \u2014 if any seat in the request fails to lock, all already-acquired locks are released immediately</li></ul><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#F78C6C;">var</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">lockedSeats</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Dictionary</span><span style="color:#89DDFF;">&lt;</span><span style="color:#FFCB6B;">Guid</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">string&gt;();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">foreach</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">var</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">seatId</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">in</span><span style="color:#A6ACCD;"> request</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">SeatIds</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F78C6C;">var</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">lockValue</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">await</span><span style="color:#A6ACCD;"> _seatLockService</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">TryLockSeatAsync</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">screening</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Id</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> seatId</span><span style="color:#89DDFF;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">if</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">lockValue </span><span style="color:#89DDFF;">==</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">null)</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;">        </span><span style="color:#676E95;">// Release everything acquired so far</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">foreach</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">var</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">kv</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">in</span><span style="color:#A6ACCD;"> lockedSeats</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#F78C6C;">await</span><span style="color:#A6ACCD;"> _seatLockService</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">ReleaseSeatAsync</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">screening</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Id</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> kv</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Key</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> kv</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Value</span><span style="color:#89DDFF;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">return</span><span style="color:#A6ACCD;"> Result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Failure</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Seat is already being reserved</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">);</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">    lockedSeats</span><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">seatId</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> lockValue</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>Locks are always released in a <code>finally</code> block after the DB write completes.</p><h3 id="what-redis-protects-against" tabindex="-1">What Redis protects against <a class="header-anchor" href="#what-redis-protects-against" aria-hidden="true">#</a></h3><p>49 out of 50 concurrent requests for the same seat are rejected immediately at the Redis layer, before any database load. This keeps the DB write path clean and fast under contention.</p><h3 id="what-redis-does-not-guarantee" tabindex="-1">What Redis does not guarantee <a class="header-anchor" href="#what-redis-does-not-guarantee" aria-hidden="true">#</a></h3><p>Redis is not a substitute for database-level consistency. A Redis node restart, network partition, or lock expiry during a slow DB write could theoretically allow two requests through simultaneously. This is where Layer 2 takes over.</p><hr><h2 id="layer-2-\u2014-optimistic-concurrency-correctness-guarantee" tabindex="-1">Layer 2 \u2014 Optimistic Concurrency (correctness guarantee) <a class="header-anchor" href="#layer-2-\u2014-optimistic-concurrency-correctness-guarantee" aria-hidden="true">#</a></h2><p>The <code>ScreeningSeat</code> entity carries an EF Core <code>[Timestamp]</code> concurrency token:</p><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">class</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">ScreeningSeat</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">ScreeningSeatStatus</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Status</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">get</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">private</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">set</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">[</span><span style="color:#FFCB6B;">Timestamp</span><span style="color:#89DDFF;">]</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">uint</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Version</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">get</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">private</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">set</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>When a seat is updated, EF Core includes the original <code>Version</code> value in the <code>WHERE</code> clause:</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki"><code><span class="line"><span style="color:#F78C6C;">UPDATE</span><span style="color:#A6ACCD;"> ScreeningSeats</span></span>
<span class="line"><span style="color:#F78C6C;">SET</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">Status</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">Reserved</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">, ...</span></span>
<span class="line"><span style="color:#F78C6C;">WHERE</span><span style="color:#A6ACCD;"> SeatId </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> @seatId </span><span style="color:#F78C6C;">AND</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">Version</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> @originalVersion</span></span>
<span class="line"></span></code></pre></div><p>If another request has already updated the row, <code>Version</code> will have changed and the update affects 0 rows. EF Core detects this and throws a <code>DbUpdateConcurrencyException</code>, which is caught and returned as a failure:</p><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#89DDFF;">catch</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">ConcurrencyException</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">return</span><span style="color:#A6ACCD;"> Result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Failure</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Seats are no longer available.</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">);</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><h3 id="what-optimistic-concurrency-protects-against" tabindex="-1">What optimistic concurrency protects against <a class="header-anchor" href="#what-optimistic-concurrency-protects-against" aria-hidden="true">#</a></h3><p>Any race condition that slips past the Redis layer. It is the hard consistency guarantee \u2014 no matter what happens at the application layer, the database will never allow two reservations for the same seat.</p><hr><h2 id="why-both-layers" tabindex="-1">Why Both Layers <a class="header-anchor" href="#why-both-layers" aria-hidden="true">#</a></h2><table><thead><tr><th></th><th>Redis Lock</th><th>Optimistic Concurrency</th></tr></thead><tbody><tr><td><strong>Purpose</strong></td><td>Fail fast, reduce DB contention</td><td>Correctness guarantee</td></tr><tr><td><strong>Where</strong></td><td>Application layer</td><td>Database layer</td></tr><tr><td><strong>Cost of failure</strong></td><td>409 returned immediately</td><td><code>DbUpdateConcurrencyException</code></td></tr><tr><td><strong>Handles</strong></td><td>Concurrent requests</td><td>Redis misses, crashes, expiry races</td></tr><tr><td><strong>Required for correctness</strong></td><td>No</td><td>Yes</td></tr></tbody></table><p>Redis is a performance optimization \u2014 it prevents the database from being hammered under contention. Optimistic concurrency is the safety net that ensures correctness even if Redis fails.</p><p>Removing Redis would still produce correct results, just with more DB load under concurrency. Removing the <code>[Timestamp]</code> token while keeping Redis would be unsafe.</p><hr><h2 id="concurrency-test" tabindex="-1">Concurrency Test <a class="header-anchor" href="#concurrency-test" aria-hidden="true">#</a></h2><p>The system is verified under load with 50 concurrent requests for the same seat:</p><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#89DDFF;">[</span><span style="color:#FFCB6B;">Fact</span><span style="color:#89DDFF;">]</span></span>
<span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">async</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Task</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">OnlyOneReservation_ShouldSucceed_ForSameSeat_UnderConcurrency</span><span style="color:#89DDFF;">()</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F78C6C;">var</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">tasks</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> Enumerable</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Range</span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">50</span><span style="color:#89DDFF;">).</span><span style="color:#82AAFF;">Select</span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">_</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">        Client</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">PostAsJsonAsync</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">/api/Reservations</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">new</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">            screeningId </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> DataSeeder</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Screening1Id</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">            seatIds </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">new</span><span style="color:#89DDFF;">[]</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> seatId </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">})</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F78C6C;">var</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">results</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">await</span><span style="color:#A6ACCD;"> Task</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">WhenAll</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">tasks</span><span style="color:#89DDFF;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">    Assert</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Equal</span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">1</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> results</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Count</span><span style="color:#89DDFF;">(</span><span style="color:#FFCB6B;">r</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=&gt;</span><span style="color:#A6ACCD;"> r</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">IsSuccessStatusCode</span><span style="color:#89DDFF;">));</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#676E95;">// Verify DB state \u2014 not just HTTP responses</span></span>
<span class="line"><span style="color:#A6ACCD;">    Assert</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Single</span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">await</span><span style="color:#A6ACCD;"> verifyDb</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Reservations</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">ToListAsync</span><span style="color:#89DDFF;">());</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>Expected outcome: exactly 1 success, 49 failures, 1 reservation row in the database.</p>`,36),p=[o];function t(r,c,i,y,D,C){return n(),a("div",null,p)}const d=s(l,[["render",t]]);export{A as __pageData,d as default};
